import { NextResponse } from "next/server";

/**
 * POST /api/reservation
 *
 * Recibe datos de reserva desde el chatbot.
 * Posteriormente enviará el payload a un webhook de n8n.
 *
 * Por ahora solo valida y confirma recepción.
 */
export async function POST(request) {
  try {
    const body = await request.json();

    const required = [
      "nombre",
      "telefono",
      "fechaEvento",
      "tipoEvento",
      "colorPreferido",
      "talleAproximado",
    ];

    const missing = required.filter((key) => !body[key]);

    if (missing.length > 0) {
      return NextResponse.json(
        {
          ok: false,
          message: `Faltan campos: ${missing.join(", ")}`,
        },
        { status: 400 },
      );
    }

    // TODO: Enviar a webhook n8n
    // await fetch(process.env.N8N_WEBHOOK_URL, {
    //   method: "POST",
    //   headers: { "Content-Type": "application/json" },
    //   body: JSON.stringify(body),
    // });

    console.info("[reservation] payload listo para n8n:", body);

    return NextResponse.json({
      ok: true,
      message:
        "Recibimos tu solicitud. Una asesora se va a comunicar con vos pronto.",
    });
  } catch {
    return NextResponse.json(
      { ok: false, message: "Error al procesar la reserva" },
      { status: 500 },
    );
  }
}
